import{_ as p,Z as a,P as o,g as l,k as d,m as n}from"./chunks/framework.Dp5g00Bf.js";const x=JSON.parse('{"title":"OpenClaude安装与使用","description":"","frontmatter":{},"headers":[],"relativePath":"views/1-开发🌏/3-运维/OpenClaude安装与使用/index.md","filePath":"views/1-开发🌏/3-运维/OpenClaude安装与使用/index.md","lastUpdated":1778336291000}'),r={name:"views/1-开发🌏/3-运维/OpenClaude安装与使用/index.md"};function i(c,e,u,h,b,g){const s=a("NolebaseGitContributors"),t=a("NolebaseGitChangelog");return o(),l("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1778336291000"},[e[0]||(e[0]=d(`<h1 id="openclaude安装与使用" tabindex="-1">OpenClaude安装与使用 <a class="header-anchor" href="#openclaude安装与使用" aria-label="Permalink to &quot;OpenClaude安装与使用&quot;">​</a></h1><p><strong>OpenClaude</strong> 是为了突破官方 Claude Code 只能使用 Anthropic 模型的限制而出现的开源项目。它本质上是一个“代理转换层”（Shim），负责将 Claude Code 的指令格式实时翻译成主流 LLM（如 OpenAI、DeepSeek、Gemini）能理解的格式。</p><p>以下是它的详细使用指南：</p><hr><h3 id="_1-核心安装方式" tabindex="-1">1. 核心安装方式 <a class="header-anchor" href="#_1-核心安装方式" aria-label="Permalink to &quot;1. 核心安装方式&quot;">​</a></h3><p>目前推荐使用** <strong><code>npm</code> 进行安装，安装后 CLI 命令为</strong> **<code>openclaude</code>。</p><p><strong>Bash</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 推荐使用 npm 安装</span></span>
<span class="line"><span>npm install -g @gitlawb/openclaude</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><hr><h3 id="_2-快速使用步骤-以-deepseek-为例" tabindex="-1">2. 快速使用步骤（以 DeepSeek 为例） <a class="header-anchor" href="#_2-快速使用步骤-以-deepseek-为例" aria-label="Permalink to &quot;2. 快速使用步骤（以 DeepSeek 为例）&quot;">​</a></h3><p>OpenClaude 通过环境变量来决定使用哪个模型及供应商。你只需要在终端执行以下三步：</p><p><strong>第一步：设置环境变量</strong> 在你的终端执行：</p><p><strong>Bash</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 告诉它你要使用 OpenAI 协议格式的供应商</span></span>
<span class="line"><span>export CLAUDE_CODE_USE_OPENAI=1</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 填入你的 API Key</span></span>
<span class="line"><span>export OPENAI_API_KEY=&quot;sk-xxxxxxxxxxxxxxxxxxxxxxxx&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 填入供应商的 API 地址（DeepSeek 为例）</span></span>
<span class="line"><span>export OPENAI_BASE_URL=&quot;https://api.deepseek.com/v1&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 告诉它使用具体模型</span></span>
<span class="line"><span>export OPENAI_MODEL=&quot;deepseek-chat&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p><strong>第二步：启动程序</strong> 直接在项目根目录下输入：</p><p><strong>Bash</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>openclaude</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>启动后，其操作体验与官方 Claude Code 完全一致。它可以自动进行文件读写、运行 Shell 命令、Git 提交等操作，但底层的逻辑推理是由你指定的模型（如 DeepSeek）完成的。</p><hr><h3 id="_3-支持的供应商配置参考" tabindex="-1">3. 支持的供应商配置参考 <a class="header-anchor" href="#_3-支持的供应商配置参考" aria-label="Permalink to &quot;3. 支持的供应商配置参考&quot;">​</a></h3><p>OpenClaude 能够自动处理协议转换，因此只要是兼容 OpenAI API 格式的供应商，你都可以通过更改** **<code>OPENAI_BASE_URL</code> 进行替换：</p><table tabindex="0"><thead><tr><th>供应商</th><th><code>OPENAI_BASE_URL</code> 示例</th><th><code>OPENAI_MODEL</code> 建议</th></tr></thead><tbody><tr><td><strong>DeepSeek</strong></td><td><code>https://api.deepseek.com/v1</code></td><td><code>deepseek-chat</code></td></tr><tr><td><strong>SiliconFlow</strong></td><td><code>https://api.siliconflow.cn/v1</code></td><td><code>Qwen/Qwen2.5-72B-Instruct</code></td></tr><tr><td><strong>Google Gemini</strong></td><td><code>https://generativelanguage.googleapis.com/v1beta/openai/</code></td><td><code>gemini-2.0-flash</code></td></tr><tr><td><strong>Local (Ollama)</strong></td><td><code>http://localhost:11434/v1</code></td><td><code>qwen2.5-coder</code></td></tr></tbody></table><hr><h3 id="_4-关键注意事项" tabindex="-1">4. 关键注意事项 <a class="header-anchor" href="#_4-关键注意事项" aria-label="Permalink to &quot;4. 关键注意事项&quot;">​</a></h3><ol><li><strong>权限透明度</strong> ：OpenClaude 本质上是一个“伪装”程序，它继承了 Claude Code 所有的 Agent 能力（包括删除文件、执行危险脚本）。<strong>请务必在你信任的代码库中使用，并确保你的 API Key 没有过高的余额上限。</strong></li><li><strong>模型推理能力的匹配</strong> ：Claude Code 原生设计是高度依赖 Claude 3.5/3.6 的** **<code>Tool Use</code>（工具调用）能力的。</li></ol><ul><li>如果你使用的模型（如较小的本地模型）推理能力不足，可能会出现**“AI 反复尝试错误命令” <strong>或</strong> “无法正确解析工具调用结果”**的情况。</li><li><strong>建议</strong> ：优先使用 DeepSeek V3/R1、GPT-4o 或 Claude 3.5 Sonnet 作为后端，以获得最佳的自动化体验。</li></ul><ol><li><strong>配置持久化</strong> ：为了避免每次打开终端都要 export，建议将上述** <strong><code>export</code> 语句添加到你的 Shell 配置文件中（如</strong> <strong><code>~/.zshrc</code> 或</strong> **<code>~/.bashrc</code>）。</li></ol>`,27)),n(s),n(t)])}const _=p(r,[["render",i]]);export{x as __pageData,_ as default};
